-- ============================================================================
-- Quiz Seed: 1 Chronicles — Part 1 (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
-- kids: 3 Qs, teens: 5 Qs, adults: 8 Qs per chapter
-- correct_answer is always 'a'
-- ============================================================================

-- ═══ 1 Chronicles Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 1, 'kids', 1, 'Who was the first man listed in the genealogy of 1 Chronicles chapter 1?', 'Adam', 'Noah', 'Abraham', 'Seth', 'a', '1 Chronicles 1:1 — "Adam, Sheth, Enosh."'),
('1 Chronicles', 1, 'kids', 2, 'What was the name of Abraham''s father?', 'Terah', 'Nahor', 'Serug', 'Eber', 'a', '1 Chronicles 1:26 — "Serug, Nahor, Terah."'),
('1 Chronicles', 1, 'kids', 3, 'Which of Abraham''s two sons are listed in chapter 1?', 'Isaac and Ishmael', 'Isaac and Esau', 'Ishmael and Lot', 'Jacob and Esau', 'a', '1 Chronicles 1:28 — "The sons of Abraham; Isaac, and Ishmael."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 1, 'teens', 1, 'How many sons of Noah are named in 1 Chronicles 1, and who are they?', 'Three: Shem, Ham, and Japheth', 'Two: Shem and Japheth', 'Three: Shem, Ham, and Canaan', 'Four: Shem, Ham, Japheth, and Arpachshad', 'a', '1 Chronicles 1:4 — "Noah, Shem, Ham, and Japheth."'),
('1 Chronicles', 1, 'teens', 2, 'Who was Nimrod, as described in the parallel passage the Chronicler echoes, and which son of Ham was his father?', 'A mighty one on earth; son of Cush', 'A king of Babylon; son of Mizraim', 'A hunter before the LORD; son of Canaan', 'A warrior of Nineveh; son of Put', 'a', '1 Chronicles 1:10 — "And Cush begat Nimrod: he began to be mighty upon the earth."'),
('1 Chronicles', 1, 'teens', 3, 'In whose days was the earth divided, according to 1 Chronicles 1?', 'Peleg', 'Eber', 'Arphaxad', 'Shelah', 'a', '1 Chronicles 1:19 — "And unto Eber were born two sons: the name of the one was Peleg; because in his days the earth was divided."'),
('1 Chronicles', 1, 'teens', 4, 'Who were the twin sons of Isaac listed in 1 Chronicles 1?', 'Esau and Israel (Jacob)', 'Esau and Edom', 'Israel and Edom', 'Jacob and Esau', 'a', '1 Chronicles 1:34 — "And Abraham begat Isaac. The sons of Isaac; Esau and Israel."'),
('1 Chronicles', 1, 'teens', 5, 'What title is given to the rulers of Edom at the end of 1 Chronicles 1?', 'Dukes', 'Kings', 'Princes', 'Chiefs', 'a', '1 Chronicles 1:51 — "Hadad died also. And the dukes of Edom were; duke Timnah, duke Aliah, duke Jetheth."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 1, 'adults', 1, 'What is the theological purpose of beginning 1 Chronicles with a genealogy from Adam rather than from Abraham or Moses?', 'To place Israel''s history within the universal history of all mankind from creation', 'To prove Israel''s superiority over all other nations', 'To establish the Levitical priesthood from the earliest generations', 'To fulfill a scribal convention required for royal chronicles', 'a', '1 Chronicles 1:1 — "Adam, Sheth, Enosh" — the Chronicler traces all history back to Adam, rooting Israel in God''s universal purpose for humanity.'),
('1 Chronicles', 1, 'adults', 2, 'Which son of Ham became the ancestor of the Canaanites, listed among Ham''s descendants in 1 Chronicles 1?', 'Canaan', 'Mizraim', 'Put', 'Cush', 'a', '1 Chronicles 1:8 — "The sons of Ham; Cush, and Mizraim, Put, and Canaan."'),
('1 Chronicles', 1, 'adults', 3, 'How many kings of Edom are listed before Israel had any king, in 1 Chronicles 1?', 'Eight', 'Five', 'Seven', 'Ten', 'a', '1 Chronicles 1:43 — "Now these are the kings that reigned in the land of Edom before any king reigned over the children of Israel." Eight kings follow in verses 43–50.'),
('1 Chronicles', 1, 'adults', 4, 'What nation descended from Esau, and what other name for Esau is given in 1 Chronicles 1?', 'Edom; Esau is called Edom', 'Ammon; Esau is called the red one', 'Moab; Esau is called Seir', 'Edom; Esau is called Seir', 'a', '1 Chronicles 1:35 — "The sons of Esau; Eliphaz, Reuel, and Jeush... And the sons of Eliphaz..." — verse 43 identifies Edom as the land of Esau.'),
('1 Chronicles', 1, 'adults', 5, 'What was the name of the first king of Edom and from what city did he come?', 'Bela the son of Beor, from Dinhabah', 'Hadad the son of Bedad, from Avith', 'Samlah of Masrekah', 'Shaul of Rehoboth by the river', 'a', '1 Chronicles 1:43-44 — "Bela the son of Beor: and the name of his city was Dinhabah."'),
('1 Chronicles', 1, 'adults', 6, 'How does the Chronicler describe the sons of Joktan, and in what region did they dwell?', 'Thirteen sons dwelling from Mesha unto Sephar, a mount of the east', 'Twelve sons inhabiting the coastlands of the sea', 'Seven sons settled in the Arabian peninsula', 'Ten sons whose territories stretched to the Euphrates', 'a', '1 Chronicles 1:20-23 — the sons of Joktan are listed; Genesis 10:30 gives "their dwelling was from Mesha, as thou goest unto Sephar a mount of the east."'),
('1 Chronicles', 1, 'adults', 7, 'Which of Abraham''s sons by Keturah are listed as his descendants in 1 Chronicles 1?', 'Zimran, Jokshan, Medan, Midian, Ishbak, and Shuah', 'Ishmael, Zimran, and Midian', 'Midian, Sheba, and Dedan', 'Jokshan, Midian, and Ishbak', 'a', '1 Chronicles 1:32 — "Now the sons of Keturah, Abraham''s concubine: she bare Zimran, and Jokshan, and Medan, and Midian, and Ishbak, and Shuah."'),
('1 Chronicles', 1, 'adults', 8, 'What unique statement is made about the last king of Edom listed in chapter 1, Hadad, that differs from the earlier kings?', 'No successor is named after his death, and his wife''s name and ancestry are given', 'He is said to have been slain in battle against Israel', 'He reigned the longest of all the Edomite kings', 'He is the only king said to have feared the LORD', 'a', '1 Chronicles 1:50-51 — "And Hadad died also. And the dukes of Edom were..." — the text shifts from kings to dukes, and verse 50 records his wife Mehetabel''s lineage.');

-- ═══ 1 Chronicles Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 2, 'kids', 1, 'Which of Jacob''s sons is the ancestor of King David, as shown in chapter 2?', 'Judah', 'Reuben', 'Levi', 'Benjamin', 'a', '1 Chronicles 2:3 — "The sons of Judah..." — the chapter traces Judah''s line down to David.'),
('1 Chronicles', 2, 'kids', 2, 'What was the name of David''s father?', 'Jesse', 'Obed', 'Boaz', 'Salmon', 'a', '1 Chronicles 2:12-15 — "And Boaz begat Obed, and Obed begat Jesse: And Jesse begat... David the seventh."'),
('1 Chronicles', 2, 'kids', 3, 'How many sons did Jesse have, according to 1 Chronicles 2?', 'Seven sons', 'Six sons', 'Eight sons', 'Ten sons', 'a', '1 Chronicles 2:13-15 — Jesse''s sons are listed: Eliab, Abinadab, Shimma, Nathaneel, Raddai, Ozem, David — seven sons.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 2, 'teens', 1, 'Who are listed as the twelve sons of Israel (Jacob) at the opening of 1 Chronicles 2?', 'Reuben, Simeon, Levi, Judah, Issachar, Zebulun, Dan, Joseph, Benjamin, Naphtali, Gad, Asher', 'Reuben, Simeon, Levi, Judah, Issachar, Zebulun, Joseph, Benjamin, Naphtali, Gad, Asher, Manasseh', 'Reuben, Simeon, Levi, Judah, Issachar, Zebulun, Dan, Joseph, Benjamin, Naphtali, Ephraim, Asher', 'Reuben, Simeon, Levi, Judah, Dan, Issachar, Zebulun, Joseph, Benjamin, Naphtali, Gad, Asher', 'a', '1 Chronicles 2:1-2 — "These are the sons of Israel; Reuben, Simeon, Levi, and Judah, Issachar, and Zebulun, Dan, Joseph, and Benjamin, Naphtali, Gad, and Asher."'),
('1 Chronicles', 2, 'teens', 2, 'What evil deed of Er, Judah''s firstborn, caused the LORD to slay him?', 'Er was wicked in the sight of the LORD', 'He married a Canaanite woman against God''s command', 'He worshipped the gods of Canaan', 'He refused to do his duty to his brother''s widow', 'a', '1 Chronicles 2:3 — "Er, the firstborn of Judah, was evil in the sight of the LORD; and he slew him."'),
('1 Chronicles', 2, 'teens', 3, 'Who was Boaz''s mother, as noted in the genealogy of 1 Chronicles 2?', 'Rahab', 'Ruth', 'Tamar', 'Bathshua', 'a', '1 Chronicles 2:11 — "And Nahshon begat Salma, and Salma begat Boaz." — verse 11 gives Salmon/Salma; the mother Rahab is implied from parallel accounts (Matthew 1:5).'),
('1 Chronicles', 2, 'teens', 4, 'What woman other than his wife did Caleb the son of Hezron have, and what son did she bear him?', 'His concubine Ephah, who bore Haran, Moza, and Gazez', 'His concubine Maachah, who bore Sheber and Tirhanah', 'His handmaid Bilhah, who bore Dan and Naphtali', 'His concubine Jarha, who bore Attai', 'a', '1 Chronicles 2:46 — "And Ephah, Caleb''s concubine, bare Haran, and Moza, and Gazez."'),
('1 Chronicles', 2, 'teens', 5, 'Who was the father of Tekoa, and what was Tekoa?', 'Ashur the father of Tekoa, a place name', 'Caleb the father of Tekoa, a clan name', 'Shobal the father of Tekoa, a city', 'Salma the father of Tekoa, a tribe', 'a', '1 Chronicles 2:24 — "And after that Hezron was dead in Calebephratah, then Abiah Hezron''s wife bare him Ashur the father of Tekoa."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 2, 'adults', 1, 'What does the Chronicler''s focus on Judah''s genealogy at the start of chapter 2 signal theologically?', 'That God''s redemptive purposes would be fulfilled through the Davidic line from Judah', 'That Judah was the most numerous of the tribes in the post-exilic community', 'That the Levitical priesthood descended through Judah and Levi equally', 'That Judah''s territory was the center of the restored nation', 'a', '1 Chronicles 2:3-15 — the genealogy moves directly from Judah to David, establishing the royal messianic lineage as central to the Chronicler''s purpose.'),
('1 Chronicles', 2, 'adults', 2, 'Who was Zerah, and what significance do the sons of Zerah have in 1 Chronicles 2?', 'Twin son of Judah by Tamar; his five sons include Zimri, Ethan, Heman, Calcol, and Dara', 'Son of Judah by Bathshua; ancestor of the temple singers', 'Firstborn of Perez; ancestor of the royal line', 'Son of Caleb; leader of post-exilic returnees', 'a', '1 Chronicles 2:4,6 — "And Tamar his daughter in law bare him Pharez and Zerah... And the sons of Zerah; Zimri, and Ethan, and Heman, and Calcol, and Dara: five of them in all."'),
('1 Chronicles', 2, 'adults', 3, 'What land grant is connected to Caleb son of Hezron''s family, and what city did his descendants found?', 'Caleb''s descendants are linked to Bethlehem and Kirjath-jearim', 'Caleb''s line founded Hebron and Debir', 'Caleb''s family built Lachish and Eglon', 'Caleb''s descendants settled Beersheba and Hormah', 'a', '1 Chronicles 2:50-51 — "These were the sons of Caleb... Salma the father of Bethlehem, Hareph the father of Bethgader."'),
('1 Chronicles', 2, 'adults', 4, 'Who was Segub, and what is notable about his birth and his son Jair?', 'Segub was born to Hezron by the daughter of Machir; his son Jair had twenty-three cities in Gilead', 'Segub was the firstborn of Caleb; his son Jair conquered thirty towns', 'Segub was Jerahmeel''s son; Jair governed the region of Bashan', 'Segub was son of Ram; Jair is the Jair who judged Israel for twenty-two years', 'a', '1 Chronicles 2:21-22 — "And afterward Hezron went in to the daughter of Machir... and she bare him Segub. And Segub begat Jair, who had three and twenty cities in the land of Gilead."'),
('1 Chronicles', 2, 'adults', 5, 'How does the Chronicler handle the lineage of Sheshan, who had no sons, only daughters?', 'Sheshan gave his daughter Ahlai to his Egyptian servant Jarha; their son Attai continued the line', 'Sheshan''s line ended with Ahlai and was absorbed into Judah''s general census', 'Sheshan adopted a son from the tribe of Levi to continue his name', 'Sheshan''s brother Appaim inherited his name and estate', 'a', '1 Chronicles 2:34-35 — "Now Sheshan had no sons, but daughters. And Sheshan had a servant, an Egyptian, whose name was Jarha. And Sheshan gave his daughter to Jarha his servant to wife; and she bare him Attai."'),
('1 Chronicles', 2, 'adults', 6, 'What phrase describes Judah''s wife Bathshua, giving an ethnic note about her that carries covenantal significance?', 'The daughter of Shua the Canaanitess', 'The daughter of Shua the Hivite', 'A woman of the daughters of Moab', 'The daughter of a Philistine man', 'a', '1 Chronicles 2:3 — "The sons of Judah; Er, and Onan, and Shelah: which three were born unto him of the daughter of Shua the Canaanitess."'),
('1 Chronicles', 2, 'adults', 7, 'How many sons did Jerahmeel''s first wife Abi have, and what is notable about his second wife Atarah?', 'Five sons by Abi; Atarah was the mother of Onam', 'Six sons by Abi; Atarah was a foreign woman he took in war', 'Four sons by Abi; Atarah had no children', 'Three sons by Abi; Atarah was his concubine', 'a', '1 Chronicles 2:25-26 — "And the sons of Jerahmeel the firstborn of Hezron were, Ram the firstborn, and Bunah, and Oren, and Ozem, and Ahijah. Jerahmeel had also another wife, whose name was Atarah; she was the mother of Onam."'),
('1 Chronicles', 2, 'adults', 8, 'What does the listing of Salma as "father of Bethlehem" and Hareph as "father of Bethgader" illustrate about the genealogical method in 1 Chronicles 2?', 'It shows that "father" means founder or settler of a town, mixing personal and geographical genealogy', 'It proves these men were literally the first human inhabitants of those cities', 'It demonstrates the Levitical control over key cities of Judah', 'It establishes that Bethlehem was originally a Calebite city, not a Davidic one', 'a', '1 Chronicles 2:51 — "Salma the father of Bethlehem, Hareph the father of Bethgader." — "father of" is a standard Chronicler formula for town founder/leader.');

-- ═══ 1 Chronicles Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 3, 'kids', 1, 'Where were David''s first six sons born, according to 1 Chronicles 3?', 'In Hebron', 'In Jerusalem', 'In Bethlehem', 'In Gibeah', 'a', '1 Chronicles 3:1 — "Now these were the sons of David, which were born unto him in Hebron."'),
('1 Chronicles', 3, 'kids', 2, 'Which famous king was the son of David who built the temple?', 'Solomon', 'Rehoboam', 'Absalom', 'Adonijah', 'a', '1 Chronicles 3:5 — "...and Solomon, four, of Bathshua the daughter of Ammiel."'),
('1 Chronicles', 3, 'kids', 3, 'What happened to the royal line of David around the time of the exile to Babylon?', 'It was carried captive to Babylon', 'It died out completely', 'It moved to Egypt', 'It hid in the wilderness', 'a', '1 Chronicles 3:17 — "And the sons of Jeconiah; Assir, Salathiel his son..." — the line continues through exile.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 3, 'teens', 1, 'How many sons did David have in Hebron, and who was the firstborn?', 'Six sons; the firstborn was Amnon by Ahinoam the Jezreelitess', 'Seven sons; the firstborn was Absalom', 'Six sons; the firstborn was Chileab by Abigail', 'Five sons; the firstborn was Adonijah', 'a', '1 Chronicles 3:1 — "Now these were the sons of David, which were born unto him in Hebron; the firstborn Amnon, of Ahinoam the Jezreelitess."'),
('1 Chronicles', 3, 'teens', 2, 'How many additional sons did David have in Jerusalem, besides the four born to Bathshua?', 'Nine more sons and Tamar their sister', 'Thirteen sons by various wives', 'Four sons besides the four by Bathshua', 'Seven sons in Jerusalem', 'a', '1 Chronicles 3:6-8 — "Ibhar also, and Elishama, and Eliphelet, And Nogah, and Nepheg, and Japhia, And Elishama, and Eliada, and Eliphelet, nine." Plus the four by Bathshua = thirteen in Jerusalem.'),
('1 Chronicles', 3, 'teens', 3, 'Who was the mother of Solomon, and what other name is her father given in 1 Chronicles 3 compared to 2 Samuel?', 'Bathshua daughter of Ammiel (in 2 Samuel she is Bathsheba, daughter of Eliam)', 'Haggith daughter of Talmai', 'Abigail daughter of Nahash', 'Maachah daughter of Absalom', 'a', '1 Chronicles 3:5 — "...of Bathshua the daughter of Ammiel." — 2 Samuel 11:3 calls her Bathsheba daughter of Eliam.'),
('1 Chronicles', 3, 'teens', 4, 'Name the last king of Judah before the Babylonian exile in the line given in 1 Chronicles 3.', 'Zedekiah (Mattaniah)', 'Jehoiakim', 'Jehoiachin (Jeconiah)', 'Josiah', 'a', '1 Chronicles 3:15-16 — "And the sons of Josiah were, the firstborn Johanan... And the sons of Jehoiakim: Jeconiah his son, Zedekiah his son." Zedekiah was the last reigning king.'),
('1 Chronicles', 3, 'teens', 5, 'How many generations of David''s line after Zerubbabel does 1 Chronicles 3 record, showing the genealogy''s post-exilic reach?', 'Six generations after Zerubbabel down to Anani', 'Three generations', 'Ten generations to Zerubbabel''s time', 'Four generations ending with Hananiah', 'a', '1 Chronicles 3:19-24 — from Zerubbabel the list extends through Hananiah, Pelatiah, Jeshaiah, Rephaiah, Arnan, Obadiah, Shechaniah, Shemaiah, Neariah, Elioenai, and Anani — approximately six to seven recorded generations.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 3, 'adults', 1, 'What is the theological significance of the Chronicler extending David''s genealogy beyond the exile into the post-exilic period?', 'It preserves hope in the Davidic covenant and shows the promise remained alive for the returnees', 'It justifies the authority of Zerubbabel as governor over the returned community', 'It proves that the Davidic line was never actually broken by the Babylonian conquest', 'It establishes the legal claim of certain families to temple service', 'a', '1 Chronicles 3:17-24 — by listing Jeconiah''s descendants through the exile to Zerubbabel and beyond, the Chronicler demonstrates God''s faithfulness to the Davidic covenant despite judgment.'),
('1 Chronicles', 3, 'adults', 2, 'What is the significance of listing Tamar alongside David''s sons in verse 9?', 'It acknowledges her as part of David''s household though the narrative of her assault by Amnon is not repeated', 'It establishes Tamar''s royal status as a potential ruler', 'It shows that daughters were counted in the royal census', 'It connects Tamar to the genealogy of Solomon', 'a', '1 Chronicles 3:9 — "These were all the sons of David, beside the sons of the concubines, and Tamar their sister." — her inclusion is unusual and alludes to the narrative of 2 Samuel 13.'),
('1 Chronicles', 3, 'adults', 3, 'How many total sons did David have in Jerusalem according to 1 Chronicles 3:5-8, and what does this number signify?', 'Thirteen sons in Jerusalem from various mothers, showing his extensive royal household', 'Eleven sons in Jerusalem', 'Nine sons, all born to Bathshua', 'Fourteen sons including those by concubines', 'a', '1 Chronicles 3:5-8 — four by Bathshua plus nine others (Ibhar, Elishama, Eliphelet, Nogah, Nepheg, Japhia, Elishama, Eliada, Eliphelet) = thirteen.'),
('1 Chronicles', 3, 'adults', 4, 'Who was Jeconiah (Jehoiachin), and what prophetic context makes his childless curse from Jeremiah relevant to this genealogy?', 'King of Judah taken to Babylon; Jeremiah 22:30 declared him childless as to the throne, yet 1 Chronicles 3 records his sons, resolving the tension', 'The last king of Israel taken to Assyria; his line was cursed never to return', 'King of Judah who reigned eleven years before Zedekiah replaced him', 'A priest-king whose curse prevented the rebuilding of the temple', 'a', '1 Chronicles 3:17 — "And the sons of Jeconiah; Assir, Salathiel his son." — Jeremiah 22:30 said he would be "childless" as regards the throne; the Chronicler records biological sons, showing the curse was dynastic, not biological.'),
('1 Chronicles', 3, 'adults', 5, 'Who was Zerubbabel''s father according to 1 Chronicles 3, and how does this differ from the account in Ezra?', 'Pedaiah in 1 Chronicles 3; but Shealtiel (Salathiel) in Ezra 3:2 and Haggai 1:1, possibly due to levirate marriage', 'Salathiel in both 1 Chronicles and Ezra, with no discrepancy', 'Assir in 1 Chronicles; Pedaiah in Ezra', 'Jeconiah directly in 1 Chronicles; Salathiel in Ezra', 'a', '1 Chronicles 3:19 — "And the sons of Pedaiah were, Zerubbabel." Ezra 3:2 reads "Zerubbabel the son of Shealtiel." A levirate marriage explanation is commonly offered.'),
('1 Chronicles', 3, 'adults', 6, 'What are the names of the four sons of Josiah listed in 1 Chronicles 3:15, and how do they correspond to the historical kings of the final period?', 'Johanan, Jehoiakim, Zedekiah (Mattaniah), Shallum — Shallum is likely Jehoahaz who reigned briefly', 'Jehoiakim, Jehoahaz, Zedekiah, and Jehoiachin', 'Josiah''s sons were Eliakim, Mattaniah, Shallum, and Johanan', 'Johanan, Jehoahaz, Jehoiakim, and Zedekiah', 'a', '1 Chronicles 3:15 — "And the sons of Josiah were, the firstborn Johanan, the second Jehoiakim, the third Zedekiah, the fourth Shallum." Shallum is identified with Jehoahaz (2 Kings 23:31).'),
('1 Chronicles', 3, 'adults', 7, 'How many sons did Solomon have according to 1 Chronicles 3:10, and who was the first in the line listed?', 'Only Rehoboam is listed as his son to begin the succession list', 'Solomon had ten sons; the first was Rehoboam', 'Solomon had three sons; the first was Abijah', 'Only two sons: Rehoboam and Jeroboam', 'a', '1 Chronicles 3:10 — "And Solomon''s son was Rehoboam, Abia his son, Asa his son, Jehoshaphat his son." — the Chronicler lists the succession line, beginning with Rehoboam.'),
('1 Chronicles', 3, 'adults', 8, 'What does the name Anani, the last name in 1 Chronicles 3:24, possibly mean, and why do some scholars see messianic significance in it?', 'Anani means "cloud" or "he who comes with clouds," and some connect it to Daniel 7:13 — one coming with the clouds of heaven', 'Anani means "the LORD answers" and refers to post-exilic prayer', 'Anani means "my affliction" marking the end of suffering in exile', 'Anani means "the remnant" symbolizing the survivors of Babylon', 'a', '1 Chronicles 3:24 — "And the sons of Elioenai were, Hodaiah, and Eliashib, and Pelaiah, and Akkub, and Johanan, and Dalaiah, and Anani, seven." — Anani from ''anan (cloud) is noted by some Jewish and Christian interpreters as messianic.');

-- ═══ 1 Chronicles Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 4, 'kids', 1, 'What did Jabez pray that God would do to his territory?', 'Enlarge his coast (border)', 'Give him many children', 'Make him a great warrior', 'Protect him from enemies', 'a', '1 Chronicles 4:10 — "Oh that thou wouldest... enlarge my coast."'),
('1 Chronicles', 4, 'kids', 2, 'Did God answer Jabez''s prayer?', 'Yes, God granted him that which he requested', 'No, the prayer was not answered', 'The Bible does not say', 'God answered only part of his prayer', 'a', '1 Chronicles 4:10 — "And God granted him that which he requested."'),
('1 Chronicles', 4, 'kids', 3, 'Which tribe''s descendants are listed in chapter 4 alongside more of Judah''s line?', 'Simeon', 'Reuben', 'Levi', 'Dan', 'a', '1 Chronicles 4:24 — "The sons of Simeon were, Nemuel, and Jamin, Jarib, Zerah, and Shaul."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 4, 'teens', 1, 'Why was Jabez more honourable than his brothers, and what does his name mean?', 'His mother bore him with sorrow and named him Jabez meaning "pain/sorrow"; yet he was more honourable', 'He was wiser than his brothers and studied the law night and day', 'He was the firstborn and received a double portion of the inheritance', 'He was set apart from birth as a Nazirite', 'a', '1 Chronicles 4:9 — "And Jabez was more honourable than his brethren: and his mother called his name Jabez, saying, Because I bare him with sorrow."'),
('1 Chronicles', 4, 'teens', 2, 'What four petitions did Jabez make to the God of Israel in his prayer?', 'That God bless him, enlarge his border, that God''s hand be with him, and keep him from evil to not cause pain', 'That God give him sons, enlarge his land, defeat his enemies, and keep him from sin', 'That God bless his work, give him wisdom, enlarge his household, and protect his children', 'That God hear his prayer, give him strength, enlarge his tribe, and grant him long life', 'a', '1 Chronicles 4:10 — "Oh that thou wouldest bless me indeed, and enlarge my coast, and that thine hand might be with me, and that thou wouldest keep me from evil, that it may not grieve me!"'),
('1 Chronicles', 4, 'teens', 3, 'What craft or trade did the family of Joab the son of Seraiah carry on at the Valley of Charashim?', 'They were craftsmen (artificers); the valley name means "valley of craftsmen"', 'They were scribes and keepers of the law', 'They were potters who made vessels for the temple', 'They were musicians for the house of the LORD', 'a', '1 Chronicles 4:14 — "And Joab, the father of the valley of Charashim; for they were craftsmen."'),
('1 Chronicles', 4, 'teens', 4, 'What does the text say about the Simeonites'' growth as they spread out under King Hezekiah?', 'They spread greatly because their land was too small; they went to the entrance of Gedor seeking pasture', 'They decreased in number and were absorbed into Judah''s territory', 'They moved north into Ephraim''s territory during the reign of Hezekiah', 'They conquered the Philistine cities of Gath and Ashdod', 'a', '1 Chronicles 4:38-39 — "These mentioned by their names were princes in their families: and the house of their fathers increased greatly. And they went to the entrance of Gedor."'),
('1 Chronicles', 4, 'teens', 5, 'In the days of Hezekiah, the Simeonites attacked the Amalekites on which mountain and have dwelt there to this day?', 'Mount Seir', 'Mount Hermon', 'Mount Carmel', 'Mount Sinai', 'a', '1 Chronicles 4:42-43 — "And some of them... went to mount Seir, having for their captains Pelatiah, and Neariah... and they smote the rest of the Amalekites that were escaped, and dwelt there unto this day."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 4, 'adults', 1, 'What literary and theological role does the Jabez episode play within the genealogical lists of 1 Chronicles 4?', 'It interrupts the lists to model the power of prayer and show that God rewards faith, not merely birth status', 'It establishes Jabez as the legal heir to Caleb''s territorial promises', 'It proves that the curse of a difficult birth can only be reversed by priestly intercession', 'It marks the transition from Judah''s genealogy to Simeon''s', 'a', '1 Chronicles 4:9-10 — the Jabez narrative breaks the genealogical pattern to demonstrate that God''s blessing is available through prayer, not just lineage.'),
('1 Chronicles', 4, 'adults', 2, 'Who were the sons of Shelah the son of Judah listed in 1 Chronicles 4, and what crafts are associated with his descendants?', 'Er (father of Lecah), Laadah (father of Mareshah), and the families of linen workers and potters', 'Pharez, Zerah, and Shobal; their families were scribes and weavers', 'Onan and Judah''s sons by Tamar; potters and smiths', 'Caleb, Jerahmeel, and Ram; their families were musicians', 'a', '1 Chronicles 4:21-23 — "The sons of Shelah the son of Judah were, Er the father of Lecah... and the families of the house of them that wrought fine linen, of the house of Ashbea... These were the potters."'),
('1 Chronicles', 4, 'adults', 3, 'What does the phrase "these are ancient things" in 1 Chronicles 4:22 suggest about the Chronicler''s use of sources?', 'It acknowledges he is citing very old records, admitting the incompleteness or uncertainty of his sources', 'It claims divine revelation for the oldest genealogies', 'It dismisses the ancient records as no longer relevant to post-exilic Israel', 'It marks the end of the Judah section and the beginning of a new source document', 'a', '1 Chronicles 4:22 — "And Jokim, and the men of Chozeba, and Joash, and Saraph, who had the dominion in Moab... And these are ancient things." — the phrase signals the Chronicler''s awareness of using archaic sources.'),
('1 Chronicles', 4, 'adults', 4, 'How does the territory of Simeon relate to Judah''s territory in the post-conquest period, and how does 1 Chronicles 4 reflect this?', 'Simeon''s allotment was within Judah''s borders (Joshua 19:1); the Chronicler notes their spread and expansion, implying Simeon became subsumed into Judah', 'Simeon had an independent territory north of Judah along the Jordan River', 'Simeon replaced Dan as the southernmost tribe after the exile', 'Simeon''s territory was east of the Jordan, absorbed into Gad', 'a', '1 Chronicles 4:24-43 — Simeon''s genealogy follows Judah''s, and their settlements (Beersheba, Hormah, Ziklag, etc.) were within Judah''s allotment per Joshua 19:1.'),
('1 Chronicles', 4, 'adults', 5, 'Who was Caleb son of Hur (not Caleb son of Jephunneh), and what does his lineage contribute to the Judah genealogy in chapter 4?', 'He was the son of Hur the firstborn of Ephrathah, the founder of Bethlehem, linking the clan of Judah to the city of David''s birth', 'He was the spy who entered Canaan with Joshua', 'He was the son of Caleb son of Jephunneh, a military commander under Joab', 'He was a descendant of Zerah who helped build Jerusalem', 'a', '1 Chronicles 4:1,4 — "The sons of Judah; Pharez, Hezron, and Carmi, and Hur, and Shobal... and the sons of Hur; Shobal the father of Kirjathjearim... Salma the father of Bethlehem."'),
('1 Chronicles', 4, 'adults', 6, 'What are the "royal potteries" mentioned in 1 Chronicles 4:23, and what do they tell us about the descendants of Shelah?', 'They were potters who lived among plants and hedges, working for the king — indicating royal artisan guilds among Judah''s clans', 'They were royal scribes who kept records for the king in Hebron', 'They were builders who constructed the royal palace under Solomon', 'They were tax collectors for the king dwelling in the Shephelah', 'a', '1 Chronicles 4:23 — "These were the potters, and those that dwelt among plants and hedges: there they dwelt with the king for his work." — royal artisan service.'),
('1 Chronicles', 4, 'adults', 7, 'What does the expansion of the Simeonites into territory belonging to Ham tell us about conditions during Hezekiah''s reign?', 'It shows territorial expansion southward into Hamite lands (traditionally Canaanite/Amalekite areas) as Simeon grew too large for its original allotment', 'It proves Hezekiah conquered Edom and Moab for Israel', 'It demonstrates Simeon acted independently of Judah during the Assyrian crisis', 'It reflects Simeon''s absorption of Philistine coastal territory', 'a', '1 Chronicles 4:40-41 — "And they found fat pasture and good... of Ham. And these written by name came in the days of Hezekiah king of Judah, and smote their tents."'),
('1 Chronicles', 4, 'adults', 8, 'How do the genealogies of 1 Chronicles 4 serve the purpose of the post-exilic community in their historical context?', 'They establish land claims, tribal identity, and occupational guilds for the returning exiles, connecting them to their ancestral heritage in the land', 'They serve primarily as historical documentation without practical application', 'They justify the political authority of Zerubbabel over post-exilic Judah', 'They record the names of those who volunteered to rebuild the temple walls', 'a', '1 Chronicles 4 — the lists of towns and families served returning exiles in establishing legitimate claims to ancestral lands and preserving identity as distinct clans within the restored community.');

-- ═══ 1 Chronicles Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 5, 'kids', 1, 'Why did Reuben lose his birthright as Jacob''s firstborn son?', 'He defiled his father''s bed (lay with his father''s concubine)', 'He sold his brother Joseph', 'He refused to lead the family', 'He worshipped false gods', 'a', '1 Chronicles 5:1 — "For he defiled his father''s bed, his birthright was given unto the sons of Joseph."'),
('1 Chronicles', 5, 'kids', 2, 'Which tribe won a great battle because they cried to God during the fight?', 'Reuben, Gad, and half of Manasseh', 'Judah and Simeon', 'Ephraim and Manasseh', 'Benjamin and Levi', 'a', '1 Chronicles 5:20 — "And they were helped against them... for they cried to God in the battle, and he was intreated of them."'),
('1 Chronicles', 5, 'kids', 3, 'Which great empire took the tribes east of the Jordan into exile?', 'Assyria', 'Babylon', 'Egypt', 'Persia', 'a', '1 Chronicles 5:26 — "And the God of Israel stirred up the spirit of Pul king of Assyria... and he carried them away."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 5, 'teens', 1, 'Although Reuben lost the birthright, who received the privileges of the firstborn, and who received the ruler''s sceptre?', 'Joseph received the birthright (double portion); Judah received the ruler''s sceptre', 'Judah received both the birthright and the sceptre', 'Levi received the birthright as priestly firstborn; Judah received the sceptre', 'Simeon received the double portion; Judah received the sceptre', 'a', '1 Chronicles 5:1-2 — "The birthright was given unto the sons of Joseph... and Judah prevailed above his brethren, and of him came the chief ruler."'),
('1 Chronicles', 5, 'teens', 2, 'Who was the mighty man of valor in Reuben''s line, and what territory did the Reubenites occupy?', 'Beerah the prince, carried away by Tiglath-pilneser; they occupied from Aroer to Nebo and Baal-meon', 'Adina the captain; they occupied from Jericho to Gilead', 'Joel the chief; they occupied from the Jordan to Mount Hermon', 'Shemaiah the prince; they held the Negev and the Wilderness of Paran', 'a', '1 Chronicles 5:3-9 — "...and Beerah his son, whom Tilgath-pilneser king of Assyria carried away captive: he was prince of the Reubenites. And they dwelt in Aroer, even unto Nebo and Baal-meon."'),
('1 Chronicles', 5, 'teens', 3, 'What was the cause of the war that the Reubenites, Gadites, and half-tribe of Manasseh fought against the Hagarites?', 'They made war to take the Hagarites'' land because their cattle had multiplied in Gilead', 'The Hagarites raided their towns and stole their herds', 'The Hagarites refused to pay tribute to the king of Israel', 'They fought to defend the eastern border of the promised land', 'a', '1 Chronicles 5:9-10 — "And eastward he inhabited unto the entering in of the wilderness from the river Euphrates: because their cattle were multiplied in the land of Gilead. And in the days of Saul they made war with the Hagarites."'),
('1 Chronicles', 5, 'teens', 4, 'What spoils did the eastern tribes take from the Hagarites after their victorious battle?', 'Fifty thousand camels, two hundred fifty thousand sheep, two thousand asses, and one hundred thousand men''s souls (lives)', 'Ten thousand horses and great riches of silver and gold', 'All the cities of the Hagarites and their flocks', 'Seven thousand horses and the treasure of the Hagarite king', 'a', '1 Chronicles 5:21 — "And they took away their cattle; of their camels fifty thousand, and of sheep two hundred and fifty thousand, and of asses two thousand, and of men an hundred thousand souls."'),
('1 Chronicles', 5, 'teens', 5, 'What sin caused the God of Israel to stir up the spirit of the Assyrian king to carry the eastern tribes into exile?', 'They transgressed against the God of their fathers, going after the gods of the people of the land', 'They refused to pay tribute to the king of Judah', 'They made war against their brother tribes', 'They neglected the temple worship and Levitical tithes', 'a', '1 Chronicles 5:25 — "And they transgressed against the God of their fathers, and went a whoring after the gods of the people of the land, whom God destroyed before them."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 5, 'adults', 1, 'How does the Chronicler use the Reuben birthright notice to introduce an important distinction between genealogical rank and royal authority?', 'He separates priestly/birth privilege (birthright → Joseph) from ruling authority (sceptre → Judah), showing two streams of divine election', 'He dismisses Reuben entirely and focuses on Judah as the sole heir of all promises', 'He uses it to explain why Ephraim and Manasseh had two tribal allotments in Canaan', 'He connects Reuben''s sin to the exile of the northern kingdom as a long-term consequence', 'a', '1 Chronicles 5:1-2 — "The genealogy is not to be reckoned after the birthright. For Judah prevailed... and the birthright was Joseph''s." — the Chronicler carefully distinguishes lordship from inheritance.'),
('1 Chronicles', 5, 'adults', 2, 'What does 1 Chronicles 5:10 tell us about when the Reubenites first began fighting the Hagarites, and why is the timing significant?', 'In the days of Saul — showing the eastern tribes were actively settled and fighting for their territory during the period of the early monarchy', 'In the days of Moses — showing the conquest extended east of the Jordan from the beginning', 'In the days of David — linking eastern expansion to the consolidation of the Davidic kingdom', 'In the days of Jeroboam — marking northern kingdom military activity', 'a', '1 Chronicles 5:10 — "And in the days of Saul they made war with the Hagarites, who fell by their hand: and they dwelt in their tents throughout all the east land of Gilead."'),
('1 Chronicles', 5, 'adults', 3, 'What specific theological explanation does the Chronicler give for the eastern tribes'' victory over the Hagarites in 1 Chronicles 5:22?', 'Many fell slain because the war was of God, and they dwelt in their stead until the captivity', 'The LORD gave them a great army and superior weapons', 'The Hagarites were weakened by famine and could not resist', 'Saul''s anointing gave the whole army divine protection', 'a', '1 Chronicles 5:22 — "For there fell down many slain, because the war was of God. And they dwelt in their steads until the captivity."'),
('1 Chronicles', 5, 'adults', 4, 'How does 1 Chronicles 5 structure the narratives of Reuben, Gad, and half-Manasseh together, and what common fate unifies them?', 'All three tribes are treated as a unit east of the Jordan, sharing the Hagarite victory and ultimately the Assyrian exile as a consequence of idolatry', 'They are treated separately with independent histories and different causes of exile', 'They are grouped because they all descended from Jacob''s concubines', 'They share the same territory in Bashan and are grouped for geographical reasons alone', 'a', '1 Chronicles 5:18-26 — the Chronicler presents the three Transjordanian tribes as a military and spiritual unit, jointly victorious through prayer and jointly exiled through apostasy.'),
('1 Chronicles', 5, 'adults', 5, 'What does 1 Chronicles 5:20 teach about the conditions under which God grants military victory?', 'God gave the eastern tribes victory because they cried to God in battle and trusted in Him — showing prayer and trust as prerequisites for divine help', 'God gave victory automatically to the larger army as a sign of His covenant', 'God gave victory only when the high priest interceded before the ark', 'God gave victory because the eastern tribes kept the Sabbath before the battle', 'a', '1 Chronicles 5:20 — "And they were helped against them, and the Hagarites were delivered into their hand, and all that were with them: for they cried to God in the battle, and he was intreated of them; because they put their trust in him."'),
('1 Chronicles', 5, 'adults', 6, 'How does the Chronicler''s description of the Gadites in 1 Chronicles 5:18 emphasize military readiness?', 'Men able to bear buckler and sword, and to shoot with bow, expert in war — forty-four thousand seven hundred and sixty', 'Mighty men of valour numbering sixty thousand, skilled in all weapons of war', 'Thirty-seven thousand men carrying spear and shield, trained from youth', 'Twenty thousand warriors who had sworn an oath before the LORD', 'a', '1 Chronicles 5:18 — "The sons of Reuben, and the Gadites, and half the tribe of Manasseh, of valiant men, men able to bear buckler and sword, and to shoot with bow, and skilful in war, were four and forty thousand seven hundred and threescore."'),
('1 Chronicles', 5, 'adults', 7, 'Which two Assyrian kings are mentioned in 1 Chronicles 5:26 as being instruments of the exile of the eastern tribes?', 'Pul (Tiglath-pileser) and Tiglath-pilneser king of Assyria — who are the same king with two names', 'Sennacherib and Shalmaneser', 'Tiglath-pileser and Sargon II', 'Pul and Shalmaneser V', 'a', '1 Chronicles 5:26 — "And the God of Israel stirred up the spirit of Pul king of Assyria, and the spirit of Tilgath-pilneser king of Assyria." — most scholars identify Pul as Tiglath-pileser III''s throne name.'),
('1 Chronicles', 5, 'adults', 8, 'What lands did the half-tribe of Manasseh occupy according to 1 Chronicles 5:23, and what does this reveal about their extent?', 'From Bashan to Baal-hermon, Senir (Hermon), and Mount Hermon — a vast northern Transjordanian territory', 'From the Arnon to the Jabbok in central Transjordan', 'From Gilead to the border of Aram-Damascus', 'From the Dead Sea to the Sea of Galilee along the eastern shore', 'a', '1 Chronicles 5:23 — "And the children of the half tribe of Manasseh dwelt in the land: they increased from Bashan unto Baal-hermon and Senir, and unto mount Hermon."');

-- ═══ 1 Chronicles Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 6, 'kids', 1, 'Which tribe is the focus of chapter 6''s long genealogy?', 'Levi', 'Judah', 'Benjamin', 'Joseph', 'a', '1 Chronicles 6:1 — "The sons of Levi; Gershon, Kohath, and Merari."'),
('1 Chronicles', 6, 'kids', 2, 'What was the name of the first high priest of Israel listed in chapter 6?', 'Aaron', 'Moses', 'Eleazar', 'Phinehas', 'a', '1 Chronicles 6:3 — "And the children of Amram; Aaron, and Moses, and Miriam. The sons also of Aaron; Nadab, and Abihu, Eleazar, and Ithamar."'),
('1 Chronicles', 6, 'kids', 3, 'Which king appointed the singers to lead worship in the house of the LORD?', 'David', 'Solomon', 'Moses', 'Samuel', 'a', '1 Chronicles 6:31 — "And these are they whom David set over the service of song in the house of the LORD, after that the ark had rest."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 6, 'teens', 1, 'What were the three clans of the Levites, descended from Levi''s three sons?', 'Gershon (Gershom), Kohath, and Merari', 'Kohath, Merari, and Amram', 'Gershom, Amram, and Izhar', 'Kohath, Ithamar, and Eleazar', 'a', '1 Chronicles 6:1 — "The sons of Levi; Gershon, Kohath, and Merari."'),
('1 Chronicles', 6, 'teens', 2, 'Who were the three chief musicians David appointed, and to which Levitical clans did they belong?', 'Heman (Kohath), Asaph (Gershom), and Ethan/Jeduthun (Merari)', 'Asaph (Kohath), Heman (Merari), and Jeduthun (Gershom)', 'Heman (Gershom), Asaph (Merari), and Ethan (Kohath)', 'Chenaniah (Kohath), Asaph (Gershom), and Jeduthun (Merari)', 'a', '1 Chronicles 6:33-47 — Heman is of Kohath (v.33), Asaph of Gershom (v.39), Ethan (Jeduthun) of Merari (v.44).'),
('1 Chronicles', 6, 'teens', 3, 'What was the duty of Aaron and his sons regarding the tabernacle, as described in 1 Chronicles 6:49?', 'They offered upon the altar of burnt offering, and on the altar of incense, for all the work of the most holy place, to make atonement for Israel', 'They carried the ark whenever Israel moved camp', 'They taught the law to the people in every city of Israel', 'They guarded the entrance to the tabernacle day and night', 'a', '1 Chronicles 6:49 — "But Aaron and his sons offered upon the altar of the burnt offering, and on the altar of incense, and were appointed for all the work of the place most holy."'),
('1 Chronicles', 6, 'teens', 4, 'How many cities with their suburbs (pasturelands) were given to the sons of Aaron from the tribes of Judah, Simeon, and Benjamin?', 'Thirteen cities', 'Six cities', 'Forty-eight cities', 'Twenty cities', 'a', '1 Chronicles 6:60 — "And out of the tribe of Benjamin... all their cities throughout their families were thirteen cities." — cf. 6:54-60.'),
('1 Chronicles', 6, 'teens', 5, 'What high priestly line is traced from Eleazar son of Aaron through to Jehozadak, who went into captivity?', 'Eleazar, Phinehas, Abishua, Bukki, Uzzi, Zerahiah, Meraioth, Amariah, Ahitub, Zadok... Azariah, Seraiah, Jehozadak', 'Eleazar, Ithamar, Eli, Ahimelech, Abiathar, Zadok, Ahimaaz', 'Aaron, Nadab, Eleazar, Phinehas, Eli, Samuel, Zadok, Abiathar', 'Eleazar, Phinehas, Eli, Samuel, Zadok, Nathan, Jehozadak', 'a', '1 Chronicles 6:4-15 — the high priestly succession from Eleazar through Jehozadak is traced, ending: "And Jehozadak went into captivity, when the LORD carried away Judah and Jerusalem by the hand of Nebuchadnezzar."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 6, 'adults', 1, 'Why does the Chronicler give the Levite genealogy the longest treatment of any tribe in chapters 1-9, and what does this emphasis signal?', 'Because Levi''s role — priesthood, music, gatekeeping — was central to the legitimate worship of God that the Chronicler champions for restored Israel', 'Because Levi was the largest tribe in the post-exilic community', 'Because the Levites kept the most detailed records and the Chronicler could therefore access more data', 'Because the Levitical system had been disrupted by the exile and needed re-establishment through genealogical proof', 'a', '1 Chronicles 6 — the chapter''s length reflects the Chronicler''s theological priority: right worship through the Levitical system is the heart of Israel''s covenant life.'),
('1 Chronicles', 6, 'adults', 2, 'What is the significance of listing 22 high priests from Aaron to Ahimaaz at the dedication of Solomon''s temple in 1 Chronicles 6:4-10?', 'It demonstrates unbroken priestly succession from Sinai to the temple dedication, legitimizing the Zadokite priesthood', 'It proves that 22 generations passed between the exodus and the building of the temple', 'It establishes that the high priesthood always passed from father to firstborn son', 'It shows that every high priest served the full span of the wilderness and conquest periods', 'a', '1 Chronicles 6:10 — "He it is that executed the priest''s office in the temple that Solomon built in Jerusalem." — the line culminates at the temple dedication, giving Zadok''s priesthood Mosaic authority.'),
('1 Chronicles', 6, 'adults', 3, 'How does the placement of Samuel in Heman''s genealogy in 1 Chronicles 6:33-38 differ from the normal understanding of Samuel''s tribe, and what might the Chronicler intend?', 'Samuel is listed as a Kohathite Levite here, whereas 1 Samuel 1:1 identifies his father Elkanah as an Ephrathite; the Chronicler apparently identifies a Levite clan settled in Ephraim''s territory', 'Samuel is listed as a Judahite in 1 Chronicles 6, contradicting all other accounts', 'Samuel''s genealogy is identical in both 1 Samuel and 1 Chronicles', 'The Chronicler omits Samuel from Heman''s line entirely', 'a', '1 Chronicles 6:33-38 — Heman''s line includes Elkanah and Samuel, presenting Samuel as Levitical (Kohathite). 1 Samuel 1:1 says Elkanah was of Zuph, an Ephraimite — likely a Levite residing in Ephraim.'),
('1 Chronicles', 6, 'adults', 4, 'What is the total number of Levitical cities distributed among the tribes, and what principle governed their distribution?', 'Forty-eight cities with their suburbs, distributed proportionally among all twelve tribes to ensure Levitical presence throughout the land', 'Twenty-four cities given only to the tribes nearest the tabernacle site', 'Thirty-six cities chosen by lot from the tribal territories closest to Jerusalem', 'Forty cities given from the territories of Judah, Benjamin, and Ephraim only', 'a', '1 Chronicles 6:54-81 — forty-eight cities in all (cf. Numbers 35:7) distributed from all tribes, fulfilling Moses'' command that Levites have no territorial inheritance but cities throughout Israel.'),
('1 Chronicles', 6, 'adults', 5, 'How does the genealogy of the Levitical musicians in 1 Chronicles 6 serve the post-exilic community at the time the Chronicler wrote?', 'It legitimizes the authority of the Levitical singers to lead temple worship by tracing their lineage to David''s appointment and Moses'' time', 'It is purely historical record-keeping with no contemporary application', 'It resolves a dispute between the priestly and Levitical factions over control of the temple music', 'It establishes that only those with verified genealogical records may participate in any temple service', 'a', '1 Chronicles 6:31-48 — the Chronicler''s audience was the restored community rebuilding the temple; establishing the singers'' ancient Davidic and Mosaic credentials legitimized their ministry.'),
('1 Chronicles', 6, 'adults', 6, 'What distinctive role separated the Aaronic priests from the rest of the Levites in the tabernacle/temple service, according to 1 Chronicles 6:48-49?', 'The Levites did all manner of service of the tabernacle in general, while Aaron and his sons specifically offered on the altars and made atonement', 'The Aaronic priests carried the ark while the Levites guarded the gates', 'The Levites provided music while Aaron''s sons alone taught the law', 'The Aaronic priests alone could enter the Most Holy Place on any day', 'a', '1 Chronicles 6:48-49 — "Their brethren also the Levites were appointed unto all manner of service of the tabernacle of the house of God. But Aaron and his sons offered upon the altar of the burnt offering... for all the work of the place most holy."'),
('1 Chronicles', 6, 'adults', 7, 'How many cities did the sons of Kohath (priests and Levites) receive, and from which tribes?', 'Ten cities from Judah, Simeon, and Benjamin for the priestly sons of Aaron; ten more from Ephraim, Dan, and half-Manasseh for the other Kohathites', 'Thirteen cities from Judah and Benjamin only', 'Twenty-three cities from all the southern tribes', 'Twelve cities from Levi''s allotment in the Negev', 'a', '1 Chronicles 6:54-61 — thirteen cities to Aaron''s sons from Judah, Simeon, Benjamin; then cities from Ephraim, Dan, and half-Manasseh for the remaining Kohathites.'),
('1 Chronicles', 6, 'adults', 8, 'What is the theological message of ending Levi''s genealogy in 1 Chronicles 6:15 with Jehozadak going into captivity by Nebuchadnezzar''s hand?', 'It shows that even the priestly line was not exempt from the consequences of Israel''s covenant failure — and simultaneously implies the priesthood would be restored in God''s redemptive plan', 'It marks the permanent end of the Aaronic priesthood and the transition to a new order', 'It proves that the exile was purely a political event with no theological cause', 'It shows that the Babylonians deliberately targeted the priests to destroy Israelite religion', 'a', '1 Chronicles 6:15 — "And Jehozadak went into captivity, when the LORD carried away Judah and Jerusalem by the hand of Nebuchadnezzar." — the LORD''s agency is explicit; exile was judgment, not accident.');

-- ═══ 1 Chronicles Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 7, 'kids', 1, 'Which tribe is mentioned first in chapter 7?', 'Issachar', 'Benjamin', 'Ephraim', 'Asher', 'a', '1 Chronicles 7:1 — "Now the sons of Issachar were, Tola, and Puah, Jashub, and Shimron, four."'),
('1 Chronicles', 7, 'kids', 2, 'What tragedy happened to Ephraim''s sons Ezer and Elead?', 'The men of Gath killed them because they went down to take their cattle', 'They died in the wilderness without entering Canaan', 'They were taken captive by the Philistines', 'They drowned crossing the Jordan River', 'a', '1 Chronicles 7:21 — "Whom the men of Gath that were born in that land slew, because they came down to take away their cattle."'),
('1 Chronicles', 7, 'kids', 3, 'Who was Asher''s daughter mentioned in the genealogy of chapter 7?', 'Serah', 'Dinah', 'Milcah', 'Achsah', 'a', '1 Chronicles 7:30 — "The sons of Asher; Imnah, and Isuah, and Ishuai, and Beriah, and Serah their sister."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 7, 'teens', 1, 'How many fighting men did Issachar''s clan total according to 1 Chronicles 7?', 'Eighty-seven thousand', 'Forty-four thousand', 'Sixty-four thousand', 'Seventy-six thousand', 'a', '1 Chronicles 7:5 — "And their brethren among all the families of Issachar were valiant men of might, reckoned in all by their genealogies fourscore and seven thousand."'),
('1 Chronicles', 7, 'teens', 2, 'How did Ephraim respond to the death of his sons Ezer and Elead?', 'He mourned many days, and his brothers came to comfort him', 'He went to war against Gath immediately', 'He tore his clothes and sat in sackcloth', 'He built a monument to their memory', 'a', '1 Chronicles 7:22 — "And Ephraim their father mourned many days, and his brethren came to comfort him."'),
('1 Chronicles', 7, 'teens', 3, 'What was the name of the son born to Ephraim after the tragedy, and what does his name mean?', 'Beriah, because it went evil with his house', 'Becher, meaning firstborn', 'Shuthelah, meaning planted of God', 'Resheph, meaning burning coal', 'a', '1 Chronicles 7:23 — "And when he went in to his wife, she conceived, and bare a son, and he called his name Beriah, because it went evil with his house."'),
('1 Chronicles', 7, 'teens', 4, 'Who was Joshua''s ancestor in the genealogy given in 1 Chronicles 7?', 'Joshua was the son of Nun, son of Elishama, in Ephraim''s line', 'Joshua was the son of Caleb of the tribe of Judah', 'Joshua was descended from Manasseh through Machir', 'Joshua was of the tribe of Benjamin through Becher', 'a', '1 Chronicles 7:27 — "Non his son, Jehoshuah his son." — the line runs from Ephraim through Shuthelah to Nun to Joshua (Jehoshuah).'),
('1 Chronicles', 7, 'teens', 5, 'How many of Asher''s descendants were described as fit for military service?', 'Twenty-six thousand men', 'Forty-one thousand five hundred men', 'Fifty-three thousand four hundred men', 'Thirty-eight thousand men', 'a', '1 Chronicles 7:40 — "All these were the children of Asher, heads of their father''s house, choice and mighty men of valour, chief of the princes. And the number throughout the genealogy of them that were apt to the war and to battle was twenty and six thousand men."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 7, 'adults', 1, 'What tribes are conspicuously absent from 1 Chronicles 7, and what likely explains their omission?', 'Dan and Zebulun are absent; possibly their records were lost, they had no post-exilic community relevance, or the Chronicler had no genealogical sources for them', 'Reuben and Gad are absent because they were already covered in chapter 5', 'Simeon and Naphtali are absent because their territories were absorbed into Assyria', 'Issachar and Benjamin are absent from chapter 7 entirely', 'a', '1 Chronicles 7 — Dan and Zebulun have no genealogical sections despite being Jacob''s sons; the Chronicler offers no explanation, suggesting lost records or deliberate omission.'),
('1 Chronicles', 7, 'adults', 2, 'How does the genealogy of Manasseh in 1 Chronicles 7:14-19 introduce the daughter Maachah and Zelophehad''s daughters?', 'Maachah is identified as Machir''s wife/concubine; Zelophehad''s daughters are mentioned as having names but no male heir — echoing Numbers 27', 'Maachah is the mother of Gideon; Zelophehad''s daughters inherited Manasseh''s territory', 'Maachah was the sister of Zelophehad who married into the tribe of Judah', 'Maachah is listed as a judge over Manasseh; Zelophehad''s daughters led the tribe into Canaan', 'a', '1 Chronicles 7:15-16 — "And Machir took to wife the sister of Huppim and Shuppim, whose sister''s name was Maachah... And Zelophehad the son of Hepher had daughters."'),
('1 Chronicles', 7, 'adults', 3, 'What does the story of Ephraim''s sons raiding Gath (1 Chronicles 7:20-22) reveal about conditions in the patriarchal period?', 'It shows cattle raiding between clans was a feature of the pre-settlement period, and that conflict with Philistine-area inhabitants preceded the formal conquest under Joshua', 'It proves that the tribe of Ephraim entered Canaan before the official conquest under Joshua', 'It establishes that the Philistines occupied Gath during the time of Jacob', 'It explains why Ephraim''s territory was smaller than Manasseh''s in the conquest allotment', 'a', '1 Chronicles 7:21-22 — the incident of Ezer and Elead appears to predate the Exodus, set in Egypt or during migration, implying contact with Canaanite/Gathite populations before the formal conquest.'),
('1 Chronicles', 7, 'adults', 4, 'How does the Chronicler''s treatment of Issachar in 1 Chronicles 7:1-5 specifically emphasize military capacity over spiritual role?', 'The passage repeatedly counts warriors and mighty men by their genealogies — 36,000 under Tola alone, and 87,000 total — foregrounding military readiness', 'The text focuses on Issachar''s wisdom and understanding of the times', 'The passage lists Issachar''s judges and scribes who served the tabernacle', 'The text notes Issachar''s agricultural abundance and tribute to the king', 'a', '1 Chronicles 7:2-5 — "And the sons of Tola... were valiant men of might in their generations; whose number was in the days of David two and twenty thousand and six hundred... fourscore and seven thousand."'),
('1 Chronicles', 7, 'adults', 5, 'What does the phrase "these are the sons of Asher, heads of their father''s house, choice and mighty men of valour, chief of the princes" suggest about the Chronicler''s standard for genealogical worth?', 'Military valor and leadership qualify clans for inclusion — the Chronicler selects those whose lineages had practical significance for the community''s defense and governance', 'Only priestly families are considered worthy of the Chronicler''s detailed treatment', 'The Chronicler values agricultural productivity as the measure of tribal significance', 'Genealogical worth is determined purely by descent from Jacob''s twelve sons without qualification', 'a', '1 Chronicles 7:40 — "choice and mighty men of valour, chief of the princes" — the Chronicler consistently identifies military readiness and leadership as markers of significance.'),
('1 Chronicles', 7, 'adults', 6, 'How many sons did Benjamin have according to 1 Chronicles 7:6, and how does this compare to other lists in Genesis and Numbers?', 'Three sons: Bela, Becher, and Jediael — differing from Genesis 46:21 (ten sons) and Numbers 26:38 (five sons)', 'Five sons matching the Numbers 26 list exactly', 'Ten sons matching the Genesis 46 list', 'Seven sons unique to the Chronicler''s genealogy', 'a', '1 Chronicles 7:6 — "The sons of Benjamin; Bela, and Becher, and Jediael, three." — Genesis 46:21 lists ten, Numbers 26:38-41 lists five; the differences reflect different genealogical perspectives or time periods.'),
('1 Chronicles', 7, 'adults', 7, 'What does the mention of Sherah, Ephraim''s granddaughter, building three cities contribute to the genealogical record?', 'It is one of the rare biblical references to a woman as founder/builder of cities, showing that women could be clan leaders with lasting territorial legacies', 'It proves that Ephraim had female descendants who served as judges', 'It establishes Sherah as the founder of a priestly clan', 'It shows that lower Beth-horon was a Levitical city', 'a', '1 Chronicles 7:24 — "And his daughter was Sherah, who built Beth-horon the nether, and the upper, and Uzzen-sherah." — Sherah is exceptional in the genealogies as a female city-builder.'),
('1 Chronicles', 7, 'adults', 8, 'Why might the Chronicler place the genealogies of the northern tribes (Issachar, Benjamin, Naphtali, Manasseh, Ephraim, Asher) in chapter 7 rather than integrating them with Judah and Levi in earlier chapters?', 'The Chronicler organizes the genealogies to present Judah (ch. 2-4), Levi (ch. 6), and the remaining tribes in a supporting role, reflecting the post-exilic community''s structure with Judah and Levi at the center', 'The northern tribes were placed last because they were historically unfaithful', 'Chapter 7 follows naturally from chapter 6 in alphabetical order of tribe names', 'The placement shows the Chronicler valued northern tribes equally to Judah', 'a', '1 Chronicles 2-9 — the structure moves from Judah (longest) to Levi (second longest) to the supporting tribes, mirroring the post-exilic reality where Judah and Levi dominated the returned community.');

-- ═══ 1 Chronicles Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 8, 'kids', 1, 'Which tribe is the subject of the genealogy in 1 Chronicles chapter 8?', 'Benjamin', 'Judah', 'Ephraim', 'Manasseh', 'a', '1 Chronicles 8:1 — "Now Benjamin begat Bela his firstborn, Ashbel the second, and Aharah the third."'),
('1 Chronicles', 8, 'kids', 2, 'What famous Israelite king came from the tribe of Benjamin?', 'Saul', 'David', 'Solomon', 'Hezekiah', 'a', '1 Chronicles 8:33 — "And Ner begat Kish, and Kish begat Saul..." — chapter 8 ends with Saul''s family line.'),
('1 Chronicles', 8, 'kids', 3, 'How many sons did Benjamin''s firstborn Bela have, according to chapter 8?', 'Nine sons', 'Five sons', 'Seven sons', 'Three sons', 'a', '1 Chronicles 8:3-5 — Bela''s sons are: Addar, Gera, Abihud, Abishua, Naaman, Ahoah, Gera, Shephuphan, and Huram — nine named.');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 8, 'teens', 1, 'Who were the heads of the fathers of the inhabitants of Geba and Manahath mentioned in 1 Chronicles 8?', 'Ehud led them; Naaman, Ahiah, and Gera led some of Geba to exile to Manahath', 'Bela led the men of Geba; Shaharaim led those in Moab', 'Saul''s father Kish drove them out', 'Shimei led 600 men from Geba into Benjamin''s new territory', 'a', '1 Chronicles 8:6-7 — "And these are the sons of Ehud: these are the heads of the fathers of the inhabitants of Geba, and they removed them to Manahath: And Naaman, and Ahiah, and Gera, he removed them."'),
('1 Chronicles', 8, 'teens', 2, 'Where did Shaharaim go to have children after he divorced his wives Hushim and Baara?', 'In the country of Moab', 'In the land of Egypt', 'In the wilderness of Sinai', 'In the city of Gibeah', 'a', '1 Chronicles 8:8 — "And Shaharaim begat children in the country of Moab, after he had sent them away; Hushim and Baara were his wives."'),
('1 Chronicles', 8, 'teens', 3, 'Which Benjaminite family settled in Jerusalem and in Aijalon, and drove away the inhabitants of Gath?', 'The sons of Elpaal, and Shamed who built Ono and Lod', 'The sons of Beriah who dwelt at Jerusalem with the father of Gibeon', 'The sons of Shaharaim who returned from Moab', 'The sons of Mikloth who settled in Gibeon', 'a', '1 Chronicles 8:12-13 — "The sons of Elpaal; Eber, and Misham, and Shamed, who built Ono, and Lod, with the towns thereof: And Beriah, and Shema... who drove away the inhabitants of Gath."'),
('1 Chronicles', 8, 'teens', 4, 'What city did the Gibeon branch of Benjamin''s family inhabit, and who was the father of Gibeon?', 'The father of Gibeon was Jeiel, and his wife''s name was Maachah; they dwelt at Gibeon', 'Ner was the father of Gibeon; they dwelt in Beersheba', 'Kish the father of Gibeon settled in Gibeah of Benjamin', 'Abner was the father of Gibeon; they lived in Mizpah', 'a', '1 Chronicles 8:29 — "And at Gibeon dwelt the father of Gibeon; whose wife''s name was Maachah." — verse 33 identifies Ner and Kish in this line.'),
('1 Chronicles', 8, 'teens', 5, 'Who was the son of Jonathan son of Saul, and what connects him to the covenant David made with Saul''s house?', 'Merib-baal (Mephibosheth); David showed kindness to him for Jonathan''s sake', 'Armoni; he was the son sacrificed to the Gibeonites', 'Esh-baal (Ish-bosheth); he briefly ruled Israel after Saul''s death', 'Malchishua; he was the son killed at the battle of Gilboa', 'a', '1 Chronicles 8:34 — "And the son of Jonathan was Merib-baal; and Merib-baal begat Micah." — 2 Samuel 9 records David''s covenant kindness to Mephibosheth (Merib-baal).');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 8, 'adults', 1, 'Why does the Chronicler give Benjamin two extended genealogies (chapters 7 and 8) while many other tribes receive only brief treatment?', 'Benjamin was significant as the tribe that provided Israel''s first king (Saul) and as the tribe most closely associated with Judah and Jerusalem in the post-exilic community', 'Benjamin had the most detailed records available to the Chronicler', 'Benjamin was the largest tribe in the post-exilic community', 'Benjamin''s territory included Jerusalem and required detailed land-claim documentation', 'a', '1 Chronicles 7:6-12 and 8:1-40 — Benjamin receives double treatment because of Saul (ch. 8), proximity to Judah and Jerusalem, and the tribe''s importance to post-exilic identity.'),
('1 Chronicles', 8, 'adults', 2, 'How does 1 Chronicles 8:29-33 link the Benjaminite family at Gibeon to Saul''s royal family, and what significance does Gibeon have?', 'The Gibeon family (Jeiel/Abi-gibeon) is Kish and Ner''s ancestor, making Saul''s line Gibeonite-area Benjaminites; Gibeon was a major cultic site where Solomon later worshipped', 'Gibeon was where Saul was anointed king, linking the royal family to that site permanently', 'The family at Gibeon fled there after Saul''s death to escape Philistine occupation', 'Gibeon was a Levitical city given to Saul''s family as a royal estate', 'a', '1 Chronicles 8:29-33 — the Gibeon residents (vv. 29-32) are followed by Ner begat Kish begat Saul (v. 33), explicitly connecting Saul''s family to Gibeon.'),
('1 Chronicles', 8, 'adults', 3, 'What does the name Merib-baal mean, and how does 1 Chronicles'' use of this name differ from 2 Samuel''s use of Mephibosheth?', 'Merib-baal means "contender with Baal" or "Baal pleads"; 2 Samuel uses Mephibosheth ("from the mouth of shame") — a deliberate name change to avoid the Baal element', 'Merib-baal and Mephibosheth are completely different people in the two books', 'Merib-baal means "beloved of God" in Hebrew and is a more honorable name', 'The Chronicler uses Merib-baal as the throne name and Mephibosheth as his personal name', 'a', '1 Chronicles 8:34 — "the son of Jonathan was Merib-baal" — 2 Samuel 4:4 uses Mephibosheth. Scribal practice often replaced "Baal" with "bosheth" (shame) in later manuscripts.'),
('1 Chronicles', 8, 'adults', 4, 'What does the detailed genealogy of Saul''s line in 1 Chronicles 8:29-40 (fourteen generations after Saul) tell us about the Chronicler''s attitude toward the house of Saul?', 'Despite Saul''s failure, the Chronicler preserves his descendants'' genealogy extensively, showing respect for the Benjaminite royal family and perhaps post-exilic Saulide community members', 'The Chronicler records Saul''s line only to contrast it negatively with David''s greater and longer line', 'The fourteen generations represent the Chronicler''s prediction of when the Saulide line would end', 'The extensive genealogy was included only because Saul''s descendants had returned to Jerusalem from exile', 'a', '1 Chronicles 8:33-40 — the line continues through Merib-baal, Micah, and nine more generations. The Chronicler grants Saul''s family the dignity of continuity even while his narrative will focus on David.'),
('1 Chronicles', 8, 'adults', 5, 'What does the reference to Benjaminites who "drove away the inhabitants of Gath" in verse 13 reveal about tribal history during the period of the judges or early monarchy?', 'It preserves a memory of Benjaminite military expansion or resistance against Philistine Gath, filling a gap not covered in Judges or Samuel', 'It refers to the battle of Gath under David''s command', 'It records the Benjaminite role in Saul''s wars against the Philistines', 'It refers to the expulsion of the Gathites during the reign of Hezekiah', 'a', '1 Chronicles 8:13 — "Beriah also, and Shema, who were heads of the fathers of the inhabitants of Aijalon, who drove away the inhabitants of Gath" — an otherwise unrecorded military event.'),
('1 Chronicles', 8, 'adults', 6, 'How many of Saul''s sons are named in 1 Chronicles 8:33, and how do these compare to the sons who died at Gilboa in chapter 10?', 'Four sons: Jonathan, Malchishua, Abinadab, and Esh-baal; Gilboa (ch. 10:2) records Jonathan, Abinadab, and Malchishua killed there — Esh-baal (Ish-bosheth) survived and later claimed the kingdom', 'Three sons: only Jonathan, Malchishua, and Abinadab — no Esh-baal is listed', 'Five sons, all of whom died at Gilboa', 'Two sons survived Gilboa; two died there', 'a', '1 Chronicles 8:33 — "Jonathan, and Malchishua, and Abinadab, and Esh-baal." — 1 Chronicles 10:2 records Jonathan, Abinadab, Malchishua dying; Esh-baal was later king (2 Samuel 2:10).'),
('1 Chronicles', 8, 'adults', 7, 'What does the Chronicler''s notation that certain Benjaminites "dwelt in Jerusalem" in 1 Chronicles 8:28,32 contribute to the post-exilic audience?', 'It establishes legitimate Benjaminite claims to residence in Jerusalem, important for returned exiles seeking to re-establish household rights in the city', 'It proves Jerusalem was originally a Benjaminite city before David conquered it', 'It shows the Chronicler considered Jerusalem the exclusive possession of the tribe of Benjamin', 'It records the migration of Benjaminites from Gibeah to Jerusalem after Saul''s death', 'a', '1 Chronicles 8:28 — "These were heads of the fathers, by their generations, chief men. These dwelt in Jerusalem." — and verse 32 repeats it; such notices validated post-exilic settlement claims.'),
('1 Chronicles', 8, 'adults', 8, 'What is the name of the last descendant listed in Saul''s extended genealogy in 1 Chronicles 8:40, and what is said about his sons?', 'Ulam, whose sons were mighty men of valour, archers, and had many sons and grandsons — one hundred and fifty', 'Eleasah, who had one hundred descendants recorded', 'Azel, who had six sons named: Azrikam, Bocheru, Ishmael, Sheariah, Obadiah, Hanan', 'Rephaiah, who had seventy men of war in his household', 'a', '1 Chronicles 8:40 — "And the sons of Ulam were mighty men of valour, archers, and had many sons, and sons'' sons, an hundred and fifty." — Azel (v. 38) has six sons, and his son Ulam ends the list.');

-- ═══ 1 Chronicles Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 9, 'kids', 1, 'Who were the first to return to live in their cities after the exile, according to 1 Chronicles 9?', 'All Israel, and the priests and Levites and temple servants', 'Only the tribe of Judah', 'Only the Levites and priests', 'The soldiers and their families', 'a', '1 Chronicles 9:2 — "Now the first inhabitants that dwelt in their possessions in their cities were, the Israelites, the priests, Levites, and the Nethinims."'),
('1 Chronicles', 9, 'kids', 2, 'What important job did the gatekeepers have at the temple?', 'They watched over the doors and gates of the house of the LORD', 'They carried the ark of the covenant', 'They led the singing in worship', 'They offered the daily sacrifices', 'a', '1 Chronicles 9:17 — "And the porters were, Shallum, and Akkub, and Talmon, and Ahiman, and their brethren... keepers of the gates." — verse 19 says they kept the entry.'),
('1 Chronicles', 9, 'kids', 3, 'Who was the chief of the gatekeepers, and which tribe did he come from?', 'Shallum the son of Kore, of the sons of Asaph, of the Kohathites', 'Meshelemiah the son of Kore of the sons of Obed-edom', 'Obed-edom of the family of Jeduthun', 'Hilkiah the son of Hosah of the Merarites', 'a', '1 Chronicles 9:17,19 — "And the porters were, Shallum, and Akkub, and Talmon... And Shallum the son of Kore, the son of Ebiasaph, the son of Korah... and his fathers, over the work of the service, keepers of the entry."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 9, 'teens', 1, 'Why was Judah carried away to Babylon, according to 1 Chronicles 9:1?', 'For their transgression', 'Because of the wickedness of Manasseh alone', 'Because they refused to pay tribute to Nebuchadnezzar', 'Because the Babylonian army was too strong to resist', 'a', '1 Chronicles 9:1 — "And Judah, who were carried away to Babylon for their transgression."'),
('1 Chronicles', 9, 'teens', 2, 'What four groups are identified as the first returnees to their possessions in 1 Chronicles 9:2?', 'The Israelites, the priests, the Levites, and the Nethinims', 'The men of Judah, the men of Benjamin, the sons of Levi, and the guards', 'The priests, the elders, the scribes, and the Levites', 'The Israelites, the priests, the singers, and the gatekeepers', 'a', '1 Chronicles 9:2 — "Now the first inhabitants that dwelt in their possessions in their cities were, the Israelites, the priests, Levites, and the Nethinims."'),
('1 Chronicles', 9, 'teens', 3, 'What duties did the priests'' Levitical kin perform regarding the temple chambers and the holy articles?', 'They lodged round about the house of God, kept the opening thereof every morning, had charge of the vessels of service, and were over the shewbread, fine flour, unleavened cakes, and the anointing oil', 'They only offered the daily burnt offerings and returned home each evening', 'They guarded the outer courts and collected the tithes from the people', 'They oversaw the building maintenance and repair of the temple walls', 'a', '1 Chronicles 9:27-29 — "And they lodged round about the house of God... the opening thereof every morning pertained to them... some of them also were appointed to oversee the vessels... And some of them had the charge of the ministering vessels... the fine flour, and the wine."'),
('1 Chronicles', 9, 'teens', 4, 'Who was responsible for the baking of spice mixtures and the preparation of the incense in the temple, according to 1 Chronicles 9?', 'Some of the sons of the priests made the ointment of the spices, and Mattithiah the Levite over the things that were made in the pans', 'The high priest alone prepared the incense each year on the Day of Atonement', 'The Nethinims prepared all spices and perfumes for the temple', 'The sons of Asaph made the incense in the outer court', 'a', '1 Chronicles 9:30-31 — "And some of the sons of the priests made the ointment of the spices... And Mattithiah, one of the Levites... had the set office over the things that were made in the pans."'),
('1 Chronicles', 9, 'teens', 5, 'How long did the gatekeepers serve without rotation, and what was their arrangement for living near their posts?', 'They were in their set office, lodging round about the house of God, and opened it every morning; four chief gatekeepers stayed permanently', 'They rotated weekly like the priestly divisions, staying seven days at a time', 'They served month-long shifts and lived in the city', 'They were permanent residents of the temple courts for their entire lifetime', 'a', '1 Chronicles 9:25-27 — "And their brethren, which were in their villages, were to come after seven days from time to time with them. For these Levites, the four chief porters... lodged round about the house of God."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 9, 'adults', 1, 'What is the literary and theological function of 1 Chronicles 9 within the overall structure of chapters 1-9 (the genealogical prologue)?', 'It serves as the climax of the genealogies by showing the restored community occupying Jerusalem — the genealogical prologue ends with living people in the holy city resuming temple worship', 'It is an appendix of administrative records with no thematic connection to the preceding genealogies', 'It begins the narrative section by introducing the characters who will appear in the court history', 'It summarizes the post-exilic census and corrects errors in the earlier genealogies', 'a', '1 Chronicles 9:2-34 — the genealogical prologue (ch. 1-9) builds toward this: Israel''s identity culminates in people returning to Jerusalem and staffing the temple, the ultimate purpose of the nation.'),
('1 Chronicles', 9, 'adults', 2, 'Why does the Chronicler emphasize that the gatekeepers lodged round about the house of God and opened it every morning in verses 26-27?', 'It establishes 24/7 continuity of sacred space protection — the temple was never left unguarded — reflecting both practical security and the theological principle of constant readiness before God', 'It proves the gatekeepers were more important than the singers in the temple hierarchy', 'It shows the Levites needed housing benefit as part of their temple employment', 'It reflects a post-exilic innovation in temple administration not practiced before the exile', 'a', '1 Chronicles 9:27 — "And they lodged round about the house of God, because the charge was upon them, and the opening thereof every morning pertained to them." — unceasing watchfulness reflects the holiness of God''s house.'),
('1 Chronicles', 9, 'adults', 3, 'How does 1 Chronicles 9 indicate that the genealogical information it provides was registered in the Book of the Kings of Israel, and what does this source reference suggest?', 'Verse 1 says "all Israel were reckoned by genealogies; and, behold, they were written in the book of the kings of Israel" — indicating the Chronicler used official royal archives as sources', 'The Chronicler says an angel revealed the genealogies to Ezra at the dedication of the second temple', 'The chapter notes that Nehemiah personally compiled the genealogies from memory', 'The source reference is to the Book of the Law of Moses kept in the ark', 'a', '1 Chronicles 9:1 — "So all Israel were reckoned by genealogies; and, behold, they are written in the book of the kings of Israel and Judah, who were carried away to Babylon for their transgression."'),
('1 Chronicles', 9, 'adults', 4, 'What is the significance of 1 Chronicles 9 listing 956 men of Benjamin, 1,760 valiant men of Judah, and 212 priests in Jerusalem among the returnees?', 'The specific numbers validate the post-exilic community''s size and composition, lending credibility to the restoration and showing God''s faithfulness in preserving a remnant', 'The numbers are symbolic representations of Israel''s twelve tribes', 'The numbers are inflated by the Chronicler to glorify the post-exilic restoration', 'The numbers indicate a military muster, not a residential census', 'a', '1 Chronicles 9:3-9 — specific numbers for Judah, Benjamin, Ephraim, Manasseh, and priests ground the genealogy in historical reality for the post-exilic audience.'),
('1 Chronicles', 9, 'adults', 5, 'How does the Chronicler''s closing of the genealogical section (ch. 1-9) with a re-listing of Saul''s genealogy in 9:35-44 serve as a transition to the narrative of chapters 10 onward?', 'It acts as a bridge — the genealogies of all Israel culminate in Saul''s family, and the narrative immediately opens with Saul''s death (ch. 10), launching the Davidic story', 'It provides a corrected version of chapter 8''s genealogy that supersedes it', 'It establishes Benjamin''s pre-eminence over Judah before the Davidic kingdom begins', 'It proves that Saul''s line survived the Philistine battle and continued in Jerusalem', 'a', '1 Chronicles 9:35-44 then 10:1 — the repetition of Saul''s genealogy immediately before his death narrative is a deliberate literary hinge, closing the genealogical prologue and opening the historical narrative.'),
('1 Chronicles', 9, 'adults', 6, 'What does the function of the Levites ''over the storehouses'' and ''appointed over the vessels'' suggest about the post-exilic reorganization of temple administration?', 'It reflects a highly organized bureaucracy for temple property management — every sacred item was under named Levitical custodians — reflecting Ezra-Nehemiah era temple restoration concerns', 'It shows the Levites had replaced the priests in all temple duties by the post-exilic period', 'It indicates that the Chronicler was himself a temple storeroom administrator', 'It proves that the temple vessels returned by Cyrus required new Levitical appointment', 'a', '1 Chronicles 9:28-29 — "And some of them had the charge of the ministering vessels, that they should bring them in and out by tale. Some of them also were appointed to oversee the vessels, and all the instruments of the sanctuary."'),
('1 Chronicles', 9, 'adults', 7, 'Why does the chapter include Nethinims (temple servants) among the first returnees in verse 2, and who were the Nethinims?', 'The Nethinims were non-Israelite temple servants (possibly descendants of the Gibeonites of Joshua 9) given to assist the Levites; their early return shows the temple could function immediately upon restoration', 'The Nethinims were a sub-class of Levites who performed manual labor in the temple', 'The Nethinims were Babylonian converts who joined the returning exiles', 'The Nethinims were the descendants of the singers appointed by David', 'a', '1 Chronicles 9:2 — "the Israelites, the priests, Levites, and the Nethinims." — cf. Ezra 8:20: "the Nethinims, whom David and the princes had appointed for the service of the Levites."'),
('1 Chronicles', 9, 'adults', 8, 'What does 1 Chronicles 9:22 tell us about the origin of the gatekeeper system, and what two great figures established it?', 'David and Samuel the seer together established the gatekeepers in their set office — linking the system to prophetic authority (Samuel) and royal authority (David)', 'Moses alone established the gatekeepers at Sinai', 'Solomon established the gatekeeper system at the temple dedication', 'The gatekeepers were established by Nehemiah upon the return from exile', 'a', '1 Chronicles 9:22 — "All these which were chosen to be porters in the gates were two hundred and twelve. These did David and Samuel the seer ordain in their set office."');

-- ═══ 1 Chronicles Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('1 Chronicles', 10, 'kids', 1, 'Where did Saul die fighting the Philistines?', 'Mount Gilboa', 'Mount Carmel', 'Mount Sinai', 'Mount Hermon', 'a', '1 Chronicles 10:1 — "Now the Philistines fought against Israel; and the men of Israel fled from before the Philistines, and fell down slain in mount Gilboa."'),
('1 Chronicles', 10, 'kids', 2, 'How did Saul die?', 'He fell upon his own sword', 'He was killed by a Philistine soldier', 'He was shot by an arrow', 'He drowned crossing a river', 'a', '1 Chronicles 10:4-5 — "Therefore Saul took a sword, and fell upon it... his armourbearer... fell likewise on the sword."'),
('1 Chronicles', 10, 'kids', 3, 'Which men rescued Saul''s body and gave it a proper burial?', 'The valiant men of Jabesh-gilead', 'The men of Judah', 'The priests of Shiloh', 'David and his mighty men', 'a', '1 Chronicles 10:12 — "All the valiant men arose, and took away the body of Saul, and the bodies of his sons, and brought them to Jabesh."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Teens
('1 Chronicles', 10, 'teens', 1, 'Which three of Saul''s sons died with him at the battle of Gilboa?', 'Jonathan, Abinadab, and Malchishua', 'Jonathan, Esh-baal, and Abinadab', 'Abinadab, Malchishua, and Esh-baal', 'Jonathan, Ishui, and Esh-baal', 'a', '1 Chronicles 10:2 — "And the Philistines slew Jonathan, and Abinadab, and Malchishua, the sons of Saul."'),
('1 Chronicles', 10, 'teens', 2, 'Why did Saul ask his armourbearer to kill him with a sword?', 'He feared the uncircumcised Philistines would abuse him', 'He had been struck by an arrow and was in agony', 'He wanted to die in battle rather than surrender', 'He feared being taken alive to serve the Philistine king', 'a', '1 Chronicles 10:4 — "Then said Saul to his armourbearer, Draw thy sword, and thrust me through therewith; lest these uncircumcised come and abuse me."'),
('1 Chronicles', 10, 'teens', 3, 'What did the Philistines do with Saul''s armour and his head after his death?', 'They put his armour in the house of their gods and sent his head to proclaim victory through the land of the Philistines', 'They displayed his body on the walls of Beth-shan and buried his armour', 'They took his armour to the temple of Dagon and fastened his body to the wall', 'They buried his armour and sent his head to their king at Gath', 'a', '1 Chronicles 10:9-10 — "They put his armour in the house of their gods... And they put his armour in the house of their gods... And they fastened his head in the temple of Dagon."'),
('1 Chronicles', 10, 'teens', 4, 'What did the men of Jabesh-gilead do with Saul''s bones after they buried his body?', 'They buried his bones under the oak in Jabesh and fasted seven days', 'They built a monument to Saul in the city square', 'They returned his bones to Gibeah his home city', 'They gave his bones to his son Ish-bosheth', 'a', '1 Chronicles 10:12 — "They took away the body of Saul, and the bodies of his sons, and brought them to Jabesh, and buried their bones under the oak in Jabesh, and fasted seven days."'),
('1 Chronicles', 10, 'teens', 5, 'What specific sin involving the spirit world did the Chronicler cite as one of the reasons Saul died?', 'Saul asked counsel of a familiar spirit (the witch of Endor)', 'Saul offered burnt offerings without the priest', 'Saul refused to utterly destroy the Amalekites', 'Saul built an altar on the high place without God''s permission', 'a', '1 Chronicles 10:13 — "So Saul died for his transgression which he committed against the LORD... and also for asking counsel of one that had a familiar spirit, to enquire of it."');

INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Adults
('1 Chronicles', 10, 'adults', 1, 'What is the Chronicler''s theological verdict on why Saul died, and how does this serve as the thematic foundation for the entire narrative that follows?', 'Saul died for unfaithfulness to the LORD — breaking the LORD''s word and seeking a familiar spirit instead of God — so the kingdom was turned to David; this verdict frames all Davidic history as the reward of faithfulness', 'Saul died because God had decided to end Benjaminite rule and transfer power to Judah regardless of Saul''s behavior', 'The Chronicler blames only the Philistines militarily and offers no theological evaluation', 'Saul''s death was the inevitable result of Jonathan dying first, leaving him without a successor', 'a', '1 Chronicles 10:13-14 — "So Saul died for his transgression which he committed against the LORD... Therefore he slew him, and turned the kingdom unto David." — this is the Chronicler''s programmatic statement.'),
('1 Chronicles', 10, 'adults', 2, 'How does the Chronicler''s account of Saul''s death (ch. 10) differ in emphasis from the parallel account in 1 Samuel 31?', 'The Chronicler adds a theological explanation (vv. 13-14) entirely absent from 1 Samuel 31, interpreting the military defeat as divine judgment for specific sins', '1 Samuel 31 gives the theological verdict; 1 Chronicles 10 omits it', 'The Chronicler omits the rescue by the men of Jabesh-gilead, which 1 Samuel 31 includes', '1 Samuel 31 includes David''s mourning for Saul; 1 Chronicles omits the battle narrative', 'a', '1 Chronicles 10:13-14 — the Chronicler appends an explicit theological commentary absent in 1 Samuel 31, transforming a military narrative into a moral lesson.'),
('1 Chronicles', 10, 'adults', 3, 'What is the significance of the word "unfaithful" (ma''al) in 1 Chronicles 10:13 as the Chronicler''s key evaluative term?', 'Ma''al is a technical term in Chronicles for covenant-breaking apostasy, used consistently to explain exile and divine judgment — Saul''s death becomes the paradigm of what unfaithfulness brings', 'Ma''al simply means disobedience to a royal command in the Chronicler''s vocabulary', 'The term signals military incompetence rather than moral failure in Chronicles', 'Ma''al is used exclusively for idolatry in Chronicles and implies Saul worshipped Baal', 'a', '1 Chronicles 10:13 — "So Saul died for his transgression (ma''al) which he committed against the LORD." — ma''al appears throughout Chronicles (13:10; 2 Chr 12:2; 26:16, etc.) as the standard term for covenant violation leading to disaster.'),
('1 Chronicles', 10, 'adults', 4, 'Why does the Chronicler begin his narrative history with Saul''s death rather than his rise or reign, unlike 1 Samuel which recounts Saul''s full story?', 'The Chronicler''s purpose is to establish David''s kingdom as the central focus; Saul''s death is the necessary gateway to David''s throne, and Saul''s reign is irrelevant to this purpose', 'The Chronicler had no access to the records of Saul''s reign', 'The Chronicler begins with Saul''s death because the post-exilic community was descended from Saul', 'The Chronicler deliberately dishonors Saul by recording only his worst moment', 'a', '1 Chronicles 10:1 — the narrative opens without introduction of Saul''s birth or anointing; the Chronicler''s history is fundamentally about the Davidic covenant, and Saul appears only as its foil and predecessor.'),
('1 Chronicles', 10, 'adults', 5, 'What does 1 Chronicles 10:13 mean by saying Saul "enquired not of the LORD" — what positive alternative was available to him?', 'Saul could have enquired through the legitimate means: the Urim and Thummim via the priests or through a true prophet — but instead turned to a necromancer, showing deliberate rejection of God''s channel', 'Saul could have prayed directly to God without any priestly mediation', 'The legitimate channel was to consult the elders of Israel assembled in council', 'Saul should have consulted the written law of Moses which he had rejected', 'a', '1 Chronicles 10:14 — "And enquired not of the LORD: therefore he slew him." — the contrast is with David who consistently enquired of the LORD (1 Chr 14:10,14), via Urim and Thummim or prophets.'),
('1 Chronicles', 10, 'adults', 6, 'How does the loyalty of the men of Jabesh-gilead to Saul in 1 Chronicles 10:11-12 illuminate Israelite covenantal values?', 'Their seven-day fast and burial of Saul reflect hesed (covenant loyalty) — they honored the king who had saved them (1 Samuel 11) by risking their lives to recover his body from the Philistines', 'Their action was purely political, protecting their city from Philistine retaliation', 'The fast was a mourning ritual required by Mosaic law for the death of a king', 'Their loyalty shows Jabesh-gilead was within the tribe of Benjamin and owed tribal allegiance', 'a', '1 Chronicles 10:11-12 — "And when all Jabesh-gilead heard all that the Philistines had done to Saul, They arose... and fasted seven days." — cf. 1 Samuel 11 where Saul rescued Jabesh-gilead, creating lasting bond.'),
('1 Chronicles', 10, 'adults', 7, 'What is the theological implication of the statement "therefore he (the LORD) slew him" in 1 Chronicles 10:14?', 'It asserts divine sovereignty over the death of kings — Saul''s death was not merely a Philistine military victory but an act of God''s judgment, establishing the Chronicler''s pattern of divine retributive justice throughout his work', 'It implies God directly caused the arrow that struck Saul', 'It means the LORD withheld military assistance and allowed the natural outcome', 'It exonerates the Philistines as mere instruments with no moral culpability', 'a', '1 Chronicles 10:14 — "therefore he slew him, and turned the kingdom unto David the son of Jesse." — the Chronicler attributes Saul''s death directly to God, a pattern seen throughout Chronicles (cf. 2 Chr 21:18-19).'),
('1 Chronicles', 10, 'adults', 8, 'How does the juxtaposition of Saul''s unfaithfulness (v. 13) with the kingdom being "turned to David" (v. 14) establish the Chronicler''s doctrine of divine retribution?', 'It presents a strict pattern: covenant unfaithfulness leads to removal/death; faithfulness leads to divine blessing and dynastic establishment — a principle the Chronicler will apply consistently to every king he evaluates', 'It proves that God rewards only military skill and political wisdom in rulers', 'It establishes that Davidic kings were immune from the same judgment that struck Saul', 'It shows that the transfer of power was a human political decision that God merely endorsed', 'a', '1 Chronicles 10:13-14 — "Saul died for his transgression... therefore he slew him, and turned the kingdom unto David." — this retributive framework (sin → judgment; faithfulness → blessing) drives the entire Chronicles narrative.');
